import{_ as o,o as a,c as t,a2 as i}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"ADR-047 — Provenance manifests + license stewardship","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-047.md","filePath":"adr/ADR-047.md"}'),c={name:"adr/ADR-047.md"};function s(d,e,r,n,l,h){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-047-—-provenance-manifests-license-stewardship" tabindex="-1">ADR-047 — Provenance manifests + license stewardship <a class="header-anchor" href="#adr-047-—-provenance-manifests-license-stewardship" aria-label="Permalink to &quot;ADR-047 — Provenance manifests + license stewardship&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-07 Extends · <code>docs/adr/ADR-046.md</code> (agency-first imagery sourcing) Scope · <code>static/data/image-provenance.json</code>, <code>static/data/text-sources.json</code>, <code>static/data/source-logos.json</code>, <code>static/data/license-waivers.json</code>, <code>scripts/license-allowlist.ts</code>, <code>scripts/build-image-provenance.ts</code>, <code>scripts/validate-data.ts</code>, <code>src/lib/components/ImageCredit.svelte</code>, <code>src/routes/credits/+page.svelte</code>, <code>src/routes/+layout.svelte</code></p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>ADR-046 locks the <strong>source priority</strong> for build-time imagery (operating agency, then partner archives, then Wikimedia Commons, then NASA Images API). It does <strong>not</strong> describe how attribution survives from fetch to UI render, and does not define a stewardship contract for the editorial text we paraphrase from primary sources.</p><p>Without that contract:</p><ul><li>Per-image gallery credits drift back to a generic &quot;Imagery: NASA / Wikimedia&quot; string the next time someone touches the panel template.</li><li>License rationales are not auditable on a per-file basis.</li><li>A new image fetched into <code>static/images/**</code> can ship without a recorded source URL or license, and reviewers have no machine-checkable way to flag it.</li><li>Editorial text that was paraphrased from primary sources (NASA press kits, Wikipedia, ESA mission pages) carries no attribution at all.</li></ul><p>Orrery deploys offline, runs entirely in the browser, and re-distributes hundreds of images and tens of editorial fragments. We are downstream of the world&#39;s space agencies and Wikimedia. The &quot;highest standard&quot; the user asked for is: every image and every reused text fragment should be traceable to its origin, in machine-checked form, with the public credits page rendering that data.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Adopt a <strong>provenance-manifest model with a fail-closed pipeline</strong>.</p><h3 id="manifests" tabindex="-1">Manifests <a class="header-anchor" href="#manifests" aria-label="Permalink to &quot;Manifests&quot;">​</a></h3><ol><li><p><code>static/data/image-provenance.json</code> — one entry per shipped image. Required fields: <code>id</code>, <code>path</code>, <code>source_type</code>, <code>title</code>, <code>author</code>, <code>agency</code>, <code>source_url</code>, <code>license_short</code>, <code>license_url</code>, <code>license_rationale</code>, <code>modifications[]</code>, plus optional <code>revid</code> / <code>pageid</code> (Wikimedia) and <code>nasa_id</code> (NASA Images API). Generated at build time from existing curated maps + live Wikimedia <code>imageinfo</code> calls. Schema: <code>static/data/schemas/image-provenance.schema.json</code>.</p></li><li><p><code>static/data/text-sources.json</code> — one entry per reused or paraphrased editorial fragment. Required fields: <code>id</code>, <code>location { file, json_path?, i18n_key? }</code>, <code>category</code>, <code>relationship</code> (<code>original</code> | <code>paraphrased-from</code> | <code>quoted-from</code> | <code>translated-from</code> | <code>adapted-from</code>), <code>license_short</code>, <code>license_rationale</code>. Optional: <code>snippet</code>, <code>source_url</code>, <code>source_publisher</code>, <code>source_author</code>, <code>license_url</code>, <code>translation_status</code>, <code>translation_reviewer</code>. Schema: <code>static/data/schemas/text-sources.schema.json</code>.</p></li><li><p><code>static/data/source-logos.json</code> — masthead manifest for the public <code>/credits</code> page. Required fields: <code>id</code>, <code>name</code>, <code>kind</code>, <code>url</code>, <code>license_summary</code>. Optional <code>logo_path</code>. Schema: <code>static/data/schemas/source-logos.schema.json</code>.</p></li><li><p><code>static/data/license-waivers.json</code> — narrow exceptions to the license allowlist. Each waiver records <code>license_short</code>, <code>scope</code>, <code>justification</code>, <code>reviewer</code>, <code>decided_at</code>, optional <code>expires_at</code>. Schema: <code>static/data/schemas/license-waivers.schema.json</code>.</p></li></ol><h3 id="license-allowlist" tabindex="-1">License allowlist <a class="header-anchor" href="#license-allowlist" aria-label="Permalink to &quot;License allowlist&quot;">​</a></h3><p><code>scripts/license-allowlist.ts</code> is the canonical list of acceptable licenses (PD-NASA, PD-USGov, PD-Russia, PD-Old, PD-self, PD-trivial, CC0, CC-BY 1.0–4.0, CC-BY-IGO 3.0/4.0, CC-BY-SA 1.0–4.0, CC-BY-SA IGO 3.0/4.0, plus the project-internal <code>Orrery-Original</code> for original prose). The file also exports <code>normaliseLicenseShortName()</code> for the loose Wikimedia <code>extmetadata.LicenseShortName</code> strings.</p><p>A license outside the allowlist must be covered by a matching waiver row, or <code>validate-data</code> and <code>build-image-provenance</code> fail closed.</p><h3 id="fail-closed-pipeline" tabindex="-1">Fail-closed pipeline <a class="header-anchor" href="#fail-closed-pipeline" aria-label="Permalink to &quot;Fail-closed pipeline&quot;">​</a></h3><ul><li><p><code>scripts/build-image-provenance.ts</code> — walks <code>static/images/**</code>, <code>static/textures/</code>, <code>static/logos/</code>. For Wikimedia Commons titles (taken from the curated maps in <code>scripts/fetch-assets.ts</code>), it queries the Commons API for <code>imageinfo</code>/<code>extmetadata</code> and records <code>Artist</code>, <code>LicenseShortName</code>, <code>LicenseUrl</code>, revision id, and the Commons file-page URL. For NASA Images API entries it records the search URL and PD-NASA rationale. For curated assets (rocket reference, agency logos, lunar discs, Solar System Scope textures) it records the curated TASL string. Writes the manifest plus a diff report at <code>docs/provenance/last-fetch-diff.md</code>. Refuses to write the manifest when any required field is missing or a license is not allowed/waived.</p></li><li><p><code>scripts/validate-data.ts</code> — runs the JSON-schema check on every manifest, then four runtime invariants: every <code>image-provenance.json</code> license must be allowed/waived, every <code>entry.path</code> must resolve to a file under <code>static/</code>, no duplicate <code>entry.path</code> values, and the same allowlist + uniqueness checks for <code>text-sources.json</code> and <code>source-logos.json</code> (with <code>logo_path</code> files-on-disk).</p></li><li><p><code>npm run build</code> — runs <code>validate-data</code> before the SvelteKit build (pre-build hook). A malformed manifest cannot ship.</p></li><li><p><code>npm run fetch</code> — wraps <code>npm run fetch-assets</code> then <code>npm run build-image-provenance</code> then <code>npm run validate-data</code>. The diff report at <code>docs/provenance/last-fetch-diff.md</code> is the rolling review surface for new content; the run is considered complete only when validate-data passes.</p></li></ul><h3 id="runtime-surface" tabindex="-1">Runtime surface <a class="header-anchor" href="#runtime-surface" aria-label="Permalink to &quot;Runtime surface&quot;">​</a></h3><ul><li><p><code>src/lib/data.ts</code> exposes <code>getImageProvenanceManifest()</code>, <code>getImageProvenance(path)</code>, <code>getSourceLogos()</code>, <code>getTextSources()</code>. UI never <code>fetch</code>es JSON directly per ADR-006.</p></li><li><p><code>src/lib/components/ImageCredit.svelte</code> renders the per-image TASL line in every gallery lightbox: title, author/agency, source link, license short name + license URL, modification disclosure, and the <code>no_endorsement_disclaimer</code> string.</p></li><li><p><code>src/routes/credits/+page.svelte</code> renders the public bill of materials, grouped by source. The route is reachable from a small footer link in <code>src/routes/+layout.svelte</code> and is intentionally <strong>not</strong> in primary nav.</p></li></ul><h3 id="authoring-rule" tabindex="-1">Authoring rule <a class="header-anchor" href="#authoring-rule" aria-label="Permalink to &quot;Authoring rule&quot;">​</a></h3><p>Any new mission/planet/site copy with external provenance, any new image under <code>static/images/**</code> or <code>static/textures/**</code> or <code>static/logos/**</code>, and any new source logo must add the corresponding row in <code>text-sources.json</code>, <code>image-provenance.json</code> (auto-generated), or <code>source-logos.json</code> in the same PR. New Wikimedia entries must include their Commons filename in the appropriate curated map in <code>scripts/fetch-assets.ts</code> so <code>build-image-provenance.ts</code> can resolve them.</p><h3 id="ongoing-review-hooks" tabindex="-1">Ongoing review hooks <a class="header-anchor" href="#ongoing-review-hooks" aria-label="Permalink to &quot;Ongoing review hooks&quot;">​</a></h3><ul><li><code>npm run fetch</code> always emits the diff report and runs validate-data. Stdout shows the digest.</li><li><code>npm run build</code> chains validate-data; CI does the same on every PR.</li><li>The Milestone D backlog at <code>docs/wip/provenance-backlog.md</code> captures cadence ideas that are not yet wired (weekly link-check GH Action, PR-comment hook, Sentry breadcrumb on lightbox-without-provenance, Playwright visual regression on <code>/credits</code>, per-locale staleness checker, periodic Wikimedia category sweep). New review-cadence ideas land there.</li></ul><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><ul><li>Pulls every attribution claim into machine-checkable artefacts, so a missing field fails CI rather than slipping past human review.</li><li>Keeps the bottom-sheet panel footers stable (Milestone B contextual labels) while exposing exact per-image attribution in the lightbox.</li><li>Provides the public credits page with structured data instead of ad-hoc HTML — the same data drives <code>/credits</code> and the in-panel <code>&lt;ImageCredit&gt;</code>.</li><li>Locks the license allowlist + waiver model so unfamiliar licenses don&#39;t quietly enter the build.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Per-component inline credits.</strong> Already what we had. Drifts. Rejected.</li><li><strong>Inline <code>&lt;credit&gt;</code> JSON in each <code>static/images/**/.json</code> sidecar.</strong> Adds many small files; harder to query for /credits. Rejected.</li><li><strong>Runtime fetch from Commons / NASA on demand.</strong> Violates ADR-016 (build-time only). Rejected.</li><li><strong>Skip the text manifest, treat all text as &quot;original&quot;.</strong> Honest for UI strings but dishonest for editorial copy paraphrased from primary sources. Rejected.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive:</p><ul><li><code>/credits</code> is a complete, auditable bill of materials.</li><li>Reviewers can grep for license / publisher / source URL.</li><li>Drift is loud — a Wikimedia license change surfaces in the next fetch&#39;s diff report.</li></ul><p>Negative:</p><ul><li>More moving parts in <code>validate-data</code> and <code>build-image-provenance</code>.</li><li>Editorial copy now requires an entry in <code>text-sources.json</code> when paraphrased; minor authoring overhead.</li><li>Wikimedia API enrichment runs at fetch time; rate-limited.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li><code>scripts/build-image-provenance.ts</code> — supports <code>--offline</code> for local runs that should skip Commons enrichment and use curated fallbacks.</li><li><code>scripts/fetch-assets.ts</code> — the <code>main()</code> runner is now guarded by <code>import.meta.url === process.argv[1]</code> so the file can be imported (its curated maps are reused by the provenance builder) without re-firing the network fetch.</li><li><code>static/data/license-waivers.json</code> ships empty (<code>{ schema_version: 1, waivers: [] }</code>); the schema is enforced even with an empty list so the next waiver follows the structure.</li><li>The runtime pipeline gracefully degrades: when <code>image-provenance.json</code> is absent (fresh checkout pre-fetch), <code>getImageProvenance(path)</code> returns <code>null</code> and <code>&lt;ImageCredit&gt;</code> renders nothing — the contextual gallery footer from Milestone B is still shown. This avoids hard-failing the dev experience while keeping the contract strict in CI.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li>ADR-046 — Agency-first build-time imagery sourcing.</li><li>ADR-016 — External assets resolved at build time (transport).</li><li>ADR-006 — Mission data via <code>static/data/</code> (data layer rule).</li><li>ADR-019 — ajv schema validation on PR.</li><li>Backlog — <code>docs/wip/provenance-backlog.md</code>.</li></ul>',35)])])}const m=o(c,[["render",s]]);export{p as __pageData,m as default};
